from typing import Generic, TypeVar, Any

class BaseEntity:
    id: str

E = TypeVar("E", bound=BaseEntity)
K = TypeVar("K")

class Repo(Generic[E, K]):
    def __init__(self):
        self._E = self._resolve_entity()
        self._validate()

    def _resolve_entity(self):
        # Attempts to read the bound type from __orig_class__
        # BUG: when instantiated as UserRepo[dict](), dict does NOT satisfy
        # the TypeVar bound, but Python only raises at the later _validate
        # step — and partial parameterization hides the earlier TypeError.
        oc = getattr(self, '__orig_class__', None)
        if oc is None:
            return Any
        args = getattr(oc, '__args__', ())
        return args[0] if args else Any

    def _validate(self):
        if self._E is not Any and not (isinstance(self._E, type) and issubclass(self._E, BaseEntity)):
            raise TypeError(
                f"{self.__class__.__name__} requires bound type satisfying "
                f"BaseEntity, got {self._E}"
            )

class UserRepo(Repo[E, K]):
    pass

if __name__ == "__main__":
    repo = UserRepo[dict]()  # Too few arguments + bound violation
